detectionRules.ruleContent:
rule sim_swap {
  strings: $s1 = "sim swap" nocase
  condition: $s1
}

rule natwest_phish {
  strings: $brand = "NatWest" nocase
  condition: $brand
}

rule synth_id {
  strings: $doc = "driving licence" nocase
  condition: $doc
}

rule mule_recruit {
  strings: $s1 = "easy money" nocase
  condition: $s1
}

rule ato_toolkit {
  strings: $s1 = "session hijack" nocase
  condition: $s1
}

rule multi_brand_phish {
  strings: $s1 = "phishing panel" nocase
  condition: $s1
}

rule ai_synth_id {
  strings: $s1 = "AI generated" nocase $s2 = "credit file" nocase
  condition: all of them
}

rule mule_herder {
  strings: $s1 = "guaranteed" nocase $s2 = "forward transfers"
  condition: all of them
}

rule mobile_phish {
  strings: $s1 = "push notification" nocase $s2 = "SMS lure"
  condition: any of them
}
